-- Add role column to accounts table -- Run this script if the role column is missing
ALTER TABLE account_schema.accounts ADD COLUMN IF NOT EXISTS role VARCHAR(255) NOT NULL DEFAULT 'USER';
-- Update existing records to have a default role if NULL UPDATE account_schema.accounts SET role = 'USER' WHERE role IS NULL;

-- Add role column to accounts table -- Run this script if the role column is missing
ALTER TABLE account_schema.accounts ADD COLUMN IF NOT EXISTS role VARCHAR(255) NOT NULL DEFAULT 'USER';
-- Update existing records to have a default role if NULL UPDATE account_schema.accounts SET role = 'USER' WHERE role IS NULL;

package org.example.microserviceaccount.entity;

import jakarta.persistence.*;
import lombok.Data;
import lombok.NoArgsConstructor;
import lombok.AllArgsConstructor;

import java.time.LocalDate;

@Entity
@Table(name = "accounts")
@Data
@NoArgsConstructor
@AllArgsConstructor
public class Account {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, unique = true)
    private String userName;

    @Column(nullable = false)
    private String email;

    @Column(nullable = false)
    private String password;

    @Column(name = "created_at", nullable = false, updatable = false)
    private LocalDate createdAt;

    @Column(name = "role", nullable = false)
    private String role;

    @PrePersist
    protected void onCreate() {
        this.createdAt = LocalDate.now();
        if(this.role == null) {
            this.role = "USER";
        }
    }
}

